WITH state_data AS (SELECT "state_name", "date", "confirmed_cases", LAG("confirmed_cases", 1, 0) OVER (PARTITION BY "state_name" ORDER BY "date") AS prev_cases FROM "COVID19_NYT"."COVID19_NYT"."US_STATES"), state_new_cases AS (SELECT "state_name", "date", "confirmed_cases" - prev_cases AS daily_new_cases FROM state_data WHERE "date" >= '2020-03-01' AND "date" <= '2020-05-31'), state_top5_daily AS (SELECT "date", "state_name", daily_new_cases, ROW_NUMBER() OVER (PARTITION BY "date" ORDER BY daily_new_cases DESC, "state_name" ASC) AS daily_rank FROM state_new_cases), state_appearances AS (SELECT "state_name", COUNT(*) AS appearance_count FROM state_top5_daily WHERE daily_rank <= 5 GROUP BY "state_name"), state_ranking AS (SELECT "state_name", appearance_count, ROW_NUMBER() OVER (ORDER BY appearance_count DESC, "state_name" ASC) AS rank FROM state_appearances), fourth_state AS (SELECT "state_name" FROM state_ranking WHERE rank = 4), county_data AS (SELECT "county", "state_name", "date", "confirmed_cases", LAG("confirmed_cases", 1, 0) OVER (PARTITION BY "state_name", "county" ORDER BY "date") AS prev_cases FROM "COVID19_NYT"."COVID19_NYT"."US_COUNTIES"), county_new_cases AS (SELECT "county", "state_name", "date", "confirmed_cases" - prev_cases AS daily_new_cases FROM county_data WHERE "date" >= '2020-03-01' AND "date" <= '2020-05-31' AND "state_name" = (SELECT "state_name" FROM fourth_state)), county_top5_daily AS (SELECT "date", "county", daily_new_cases, ROW_NUMBER() OVER (PARTITION BY "date" ORDER BY daily_new_cases DESC, "county" ASC) AS daily_rank FROM county_new_cases), county_appearances AS (SELECT "county", COUNT(*) AS appearance_count FROM county_top5_daily WHERE daily_rank <= 5 GROUP BY "county"), county_ranking AS (SELECT "county", appearance_count, ROW_NUMBER() OVER (ORDER BY appearance_count DESC, "county" ASC) AS rank FROM county_appearances) SELECT 'state' AS category, "state_name" AS name, appearance_count, rank FROM state_ranking UNION ALL SELECT 'county' AS category, "county" AS name, appearance_count, rank FROM county_ranking WHERE rank <= 5 ORDER BY category, rank